65					return fmt.Errorf("failed to load configuration: %w", err)
66				}
67	
68				if baseOrgConfig == nil {
69					return fmt.Errorf("base organization configuration not found")
70				}
71	
72				orgConfig := baseOrgConfig
73	
74				// Parse blueprints list
75				var blueprintList []string
76				if blueprints != "" {
77					blueprintList = strings.Split(blueprints, ",")
78					for i := range blueprintList {
79						blueprintList[i] = strings.TrimSpace(blueprintList[i])
80					}
81				}
82	
83				// Parse exclude-blueprints (deep)
84				var excludeBlueprintList []string
