91	
92				// Parse exclude-blueprint-schema (schema-only)
93				var excludeBlueprintSchemaList []string
94				if excludeBlueprintSchema != "" {
95					excludeBlueprintSchemaList = strings.Split(excludeBlueprintSchema, ",")
96					for i := range excludeBlueprintSchemaList {
97						excludeBlueprintSchemaList[i] = strings.TrimSpace(excludeBlueprintSchemaList[i])
98					}
99				}
100	
101				// Parse per-resource ID filters
102				parseCSV := func(s string) []string {
103					if s == "" {
104						return nil
105					}
106					parts := strings.Split(s, ",")
107					for i := range parts {
108						parts[i] = strings.TrimSpace(parts[i])
109					}
110					return parts
111				}
112				entityList := parseCSV(entities)
113				scorecardList := parseCSV(scorecards)
114				actionList := parseCSV(actions)
115				pageList := parseCSV(pages)
116				integrationList := parseCSV(integrations)
117				teamList := parseCSV(teams)
118				userList := parseCSV(users)
119	
120				// Parse include list
121				var includeList []string
122				if include != "" {
123					includeList = strings.Split(include, ",")
124					for i := range includeList {
125						includeList[i] = strings.TrimSpace(includeList[i])
126					}
127	
128					// Validate resource types
129					validResources := map[string]bool{
130						"blueprints":            true,
131						"entities":              true,
132						"scorecards":            true,
133						"actions":               true,
134						"teams":                 true,
135						"users":                 true,
136						"automations":           true,
137						"pages":                 true,
138						"integrations":          true,
139						"blueprint-permissions": true,
140						"action-permissions":    true,
141						"page-permissions":      true,
142					}
143	
144					for _, r := range includeList {
145						if !validResources[r] {
146							return fmt.Errorf("invalid resource: %s. Valid resources: blueprints, entities, scorecards, actions, teams, users, automations, pages, integrations, blueprint-permissions, action-permissions, page-permissions", r)
147						}
148					}
149	
150					// page-permissions requires pages so that page identifiers can be collected
151					hasPagePerms := slices.Contains(includeList, "page-permissions")
152					hasPages := slices.Contains(includeList, "pages")
153					if hasPagePerms && !hasPages {
154						return fmt.Errorf("page-permissions requires pages to also be included (add 'pages' to --include)")
155					}
156	
157					// Handle conflict between skip_entities and include
158					if skipEntities {
159						for _, r := range includeList {
160							if r == "entities" {
161								output.WarningPrintln("Warning: --skip-entities conflicts with --include entities, ignoring --skip-entities")
162								skipEntities = false
163								break
164							}
165						}
166					}
167					if skipEntities {
168						for _, r := range includeList {
169							if r == "users" {
170								output.WarningPrintln("Warning: --skip-entities conflicts with --include users, ignoring --skip-entities")
171								skipEntities = false
172								break
173							}
174							if r == "teams" {
175								output.WarningPrintln("Warning: --skip-entities conflicts with --include teams, ignoring --skip-entities")
176								skipEntities = false
177								break
178							}
179						}
180					}
181				}
182	
183				// Auto-include resource types when ID filters are specified
184				ensureContains := func(list []string, item string) []string {
185					for _, v := range list {
186						if v == item {
187							return list
188						}
189					}
190					return append(list, item)
191				}
192				needBlueprints := false
193				if len(entityList) > 0 {
194					includeList = ensureContains(includeList, "entities")
195					needBlueprints = true
196				}
197				if len(scorecardList) > 0 {
198					includeList = ensureContains(includeList, "scorecards")
199					needBlueprints = true
200				}
201				if len(actionList) > 0 {
202					includeList = ensureContains(includeList, "actions")
203					includeList = ensureContains(includeList, "action-permissions")
204					needBlueprints = true
205				}
206				if len(pageList) > 0 {
207					includeList = ensureContains(includeList, "pages")
208					includeList = ensureContains(includeList, "page-permissions")
209				}
210				if len(integrationList) > 0 {
211					includeList = ensureContains(includeList, "integrations")
212				}
213				if len(teamList) > 0 {
214					includeList = ensureContains(includeList, "teams")
215				}
216				if len(userList) > 0 {
