231				defer exportModule.Close()
232	
233				// Show info only if not quiet and output format is text
234				if outputFormat != "json" {
235					output.Printf("\nExporting data from base organization: %s\n", orgName)
236					if orgName == "" {
237						output.Printf("(using default organization)\n")
238					}
239					output.Printf("Output file: %s\n", outputPath)
240					if len(blueprintList) > 0 {
241						output.Printf("Blueprints filter: %s\n", strings.Join(blueprintList, ", "))
242					}
243					if len(entityList) > 0 {
244						output.Printf("Entities filter: %s\n", strings.Join(entityList, ", "))
245					}
246					if len(scorecardList) > 0 {
247						output.Printf("Scorecards filter: %s\n", strings.Join(scorecardList, ", "))
248					}
249					if len(actionList) > 0 {
250						output.Printf("Actions filter: %s\n", strings.Join(actionList, ", "))
251					}
252					if len(pageList) > 0 {
253						output.Printf("Pages filter: %s\n", strings.Join(pageList, ", "))
254					}
255					if len(integrationList) > 0 {
256						output.Printf("Integrations filter: %s\n", strings.Join(integrationList, ", "))
257					}
258					if len(teamList) > 0 {
259						output.Printf("Teams filter: %s\n", strings.Join(teamList, ", "))
260					}
261					if len(userList) > 0 {
262						output.Printf("Users filter: %s\n", strings.Join(userList, ", "))
263					}
264					if len(includeList) > 0 {
265						output.Printf("Including only: %s\n", strings.Join(includeList, ", "))
266					} else if skipEntities {
267						output.Printf("Skipping entities (schema only)\n")
268					}
269				}
270	
271				// Execute export
272				result, err := exportModule.Execute(cmd.Context(), export.Options{
273					OutputPath:             outputPath,
274					Blueprints:             blueprintList,
275					ExcludeBlueprints:      excludeBlueprintList,
276					ExcludeBlueprintSchema: excludeBlueprintSchemaList,
277					Format:                 format,
278					SkipEntities:           skipEntities,
279					SkipSystemBlueprints:   skipSystemBlueprints,
280					IncludeRuleResults:     includeRuleResults,
281					IncludeResources:       includeList,
282					Entities:               entityList,
283					Scorecards:             scorecardList,
284					Actions:                actionList,
285					Pages:                  pageList,
286					Integrations:           integrationList,
287					Teams:                  teamList,
288					Users:                  userList,
289				})
290				if err != nil {
291					if outputFormat == "json" {
292						jsonResult := output.JSONResult{
293							Success: false,
294							Error:   err.Error(),
295						}
296						output.PrintJSON(jsonResult)
297						return err
298					}
299					return fmt.Errorf("export failed: %w", err)
300				}
301	
302				if !result.Success {
303					if outputFormat == "json" {
304						jsonResult := output.JSONResult{
305							Success: false,
306							Error:   fmt.Sprintf("%v", result.Error),
307						}
308						output.PrintJSON(jsonResult)
309						return fmt.Errorf("export failed: %v", result.Error)
310					}
311					return fmt.Errorf("export failed: %v", result.Error)
312				}
313	
314				// Output in JSON format if requested
315				if outputFormat == "json" {
316					jsonData := map[string]interface{}{
317						"output_path":        result.OutputPath,
318						"blueprints_count":   result.BlueprintsCount,
319						"entities_count":     result.EntitiesCount,
320						"actions_count":      result.ActionsCount,
321						"users_count":        result.UsersCount,
